import re
from typing import Dict

def get_network_info() -> Dict:
    """
    Run a shell command to get network interface information.

    Returns:
    A dictionary containing network interface information.
    """
    try:
        # Get network interface information using ip link command
        output = subprocess.run(['ip', 'link'], capture_output=True, text=True)

        # Parse the output to extract interface information
        interfaces: Dict[str, Dict] = {}
        for line in output.stdout.split('\n'):
            match = re.match(r'(\w+)\s+link/ether\s+([0-9a-f]{2}:){5}[0-9a-f]{2}', line)
            if match:
                interface_name, interface_mac = match.groups()
                interfaces[interface_name] = {'mac': interface_mac,'state': 'UP' if line.strip().endswith('state UP') else 'DOWN'}

        # Get interface IP address information using ip addr command
        ip_addr_output = subprocess.run(['ip', 'addr'], capture_output=True, text=True)
        for line in ip_addr_output.stdout.split('\n'):
            match = re.match(r'\b(\w+)\b:\s+inet\s+([0-9.]+)', line)
            if match:
                interface_name, interface_ip = match.groups()
                if interface_name in interfaces:
                    interfaces[interface_name]['ip'] = interface_ip

        return interfaces

    except Exception as e:
        print(f"Error: {e}")
        return {}
