import os

class CacheManager:
    def __init__(self, cache_path):
        self.cache_path = cache_path
        self.cached_objects = {}

    def _generate_key(self, obj):
        return hashlib.md5(str(obj).encode()).hexdigest()

    def _serialize(self, obj):
        return json.dumps(obj, separators=(',', ':'))

    def _deserialize(self, serialized_obj):
        return json.loads(serialized_obj)

    def _check_cache(self, obj):
        key = self._generate_key(obj)
        cache_file = os.path.join(self.cache_path, f'{key}.json')
        if os.path.exists(cache_file):
            with open(cache_file, 'r') as f:
                cached_obj = self._deserialize(f.read())
                self.cached_objects[key] = cached_obj
            return cached_obj
        return None

    def _store_in_cache(self, obj):
        key = self._generate_key(obj)
        cache_file = os.path.join(self.cache_path, f'{key}.json')
        serialized_obj = self._serialize(obj)
        with open(cache_file, 'w') as f:
            f.write(serialized_obj)
        self.cached_objects[key] = obj
        return obj

    def get(self, obj):
        cached_obj = self._check_cache(obj)
        if cached_obj is not None:
            return cached_obj
        return None

    def store(self, obj):
        cached_obj = self._store_in_cache(obj)
        return cached_obj


