import hashlib
import os

def find_duplicate_files(directory):
    """
    Find duplicate files in a directory by comparing SHA-256 content hashes.

    Args:
    directory (str): The path to the directory to search for duplicates.

    Returns:
    A dictionary where the keys are the paths to the duplicate files and the values are a list of paths to the duplicate files.
    """
    if not os.path.exists(directory):
        return {}

    file_hashes = {}
    duplicate_files = {}

    for root, dirs, files in os.walk(directory):
        for file in files:
            file_path = os.path.join(root, file)
            try:
                with open(file_path, 'rb') as f:
                    file_hash = hashlib.sha256(f.read()).hexdigest()
            except Exception as e:
                print(f"Error reading file {file_path}: {e}")
                continue

            if file_hash in file_hashes:
                if file_path not in file_hashes[file_hash]:
                    file_hashes[file_hash].append(file_path)
            else:
                file_hashes[file_hash] = [file_path]

    for file_hash, paths in file_hashes.items():
        if len(paths) > 1:
            duplicate_files[file_hash] = paths

    return duplicate_files
