from typing import Dict, Any

def parse_ini_config(file_path: str) -> Dict[str, Dict[str, str]]:
    """
    Parse an INI-style configuration file and return a nested dict.

    Args:
    file_path (str): Path to the INI configuration file.

    Returns:
    Dict[str, Dict[str, str]]: A nested dictionary representing the INI configuration file.

    Raises:
    configparser.Error: If there's an error parsing the configuration file.
    FileNotFoundError: If the file does not exist.
    """

    def _parse_section(config: configparser.ConfigParser, section: str) -> Dict[str, str]:
        return {key: config[section][key] for key in config[section]}

    def _parse_file(file_path: str) -> Dict[str, Any]:
        config = configparser.ConfigParser()
        try:
            config.read(file_path)
        except FileNotFoundError:
            raise FileNotFoundError(f"File '{file_path}' not found")
        except configparser.Error as e:
            raise configparser.Error(f"Error parsing file '{file_path}': {e}")

        result: Dict[str, Any] = {}
        for section in config.sections():
            result[section] = _parse_section(config, section)

        return result

    return _parse_file(file_path)
